={{ (()=>{
  // 1) ТУТ ПРОСТО ВСТАВЛЯЕШЬ ЧТО ХОЧЕШЬ
  const varsForId = [
    $('Start').first().json.comfyUiRequest
  ];

  // 2) нормализуем значения -> одна строка
  function stable(v){
    if (v === null || v === undefined) return "";
    if (typeof v === "string") return v;
    if (typeof v === "number" || typeof v === "boolean") return String(v);
    if (Array.isArray(v)) return "[" + v.map(stable).join(",") + "]";
    // объект: сортируем ключи для стабильности
    const keys = Object.keys(v).sort();
    return "{" + keys.map(k => JSON.stringify(k)+":"+stable(v[k])).join(",") + "}";
  }

  const s = varsForId.map(stable).join("|");

  // 3) FNV-1a 32-bit (2 раза, чтобы получить 16 hex)
  function fnv1a32(str){
    let h = 0x811c9dc5;
    for (let i=0; i<str.length; i++){
      h ^= str.charCodeAt(i);
      h = Math.imul(h, 0x01000193);
    }
    return (h >>> 0);
  }

  const h1 = fnv1a32(s);
  const h2 = fnv1a32("salt|" + s);

  const hex =
    h1.toString(16).padStart(8,"0") +
    h2.toString(16).padStart(8,"0");

  return `${hex.slice(0,4)}-${hex.slice(4,8)}-${hex.slice(8,12)}-${hex.slice(12,16)}`;
})() }}

